// Lazy load unused JavaScript features
(function() {
    'use strict';
    
    let loadedModules = new Set();
    
    // Load script dynamically
    function loadScript(src, callback) {
        if (loadedModules.has(src)) {
            callback && callback();
            return;
        }
        
        const script = document.createElement('script');
        script.src = src;
        script.onload = () => {
            loadedModules.add(src);
            callback && callback();
        };
        document.head.appendChild(script);
    }
    
    // Intersection Observer for lazy loading
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const element = entry.target;
                
                // Load Slick for partner sliders
                if (element.classList.contains('slick-slider2') || element.classList.contains('team-swiper')) {
                    loadScript('/assets/lib/slick-1.8.1/slick/slick.min.js', () => {
                        // Initialize slick sliders
                        if (typeof $ !== 'undefined' && $.fn.slick) {
                            initSlickSliders();
                        }
                    });
                }
                
                // Load counter animation
                if (element.classList.contains('counter-number')) {
                    initCounterAnimation();
                }
                
                observer.unobserve(element);
            }
        });
    }, { rootMargin: '50px' });
    
    // Observe elements that need lazy loading
    document.addEventListener('DOMContentLoaded', () => {
        document.querySelectorAll('.slick-slider2, .team-swiper, .counter-number').forEach(el => {
            observer.observe(el);
        });
    });
    
    // Initialize slick sliders
    function initSlickSliders() {
        if ($('.slick-slider2').length) {
            $('.slick-slider2').slick({
                dots: true,
                infinite: true,
                speed: 300,
                autoplay: true,
                autoplaySpeed: 1000,
                slidesToShow: 6,
                slidesToScroll: 1,
                centerMode: true,
                responsive: [
                    { breakpoint: 1024, settings: { slidesToShow: 3, slidesToScroll: 3, infinite: true, dots: true } },
                    { breakpoint: 600, settings: { slidesToShow: 2, slidesToScroll: 2 } },
                    { breakpoint: 480, settings: { slidesToShow: 1, slidesToScroll: 1 } }
                ]
            });
        }
        
        if ($('.team-swiper').length) {
            $('.team-swiper').slick({
                dots: true,
                infinite: false,
                speed: 300,
                autoplay: false,
                slidesToShow: 4,
                slidesToScroll: 1,
                prevArrow: '<button type="button" class="slick-prev"><i class="fas fa-chevron-left"></i></button>',
                nextArrow: '<button type="button" class="slick-next"><i class="fas fa-chevron-right"></i></button>',
                responsive: [
                    { breakpoint: 1024, settings: { slidesToShow: 3, slidesToScroll: 3, infinite: true, dots: true } },
                    { breakpoint: 600, settings: { slidesToShow: 2, slidesToScroll: 2 } },
                    { breakpoint: 480, settings: { slidesToShow: 1, slidesToScroll: 1 } }
                ]
            });
        }
    }
    
    // Initialize counter animation
    function initCounterAnimation() {
        let counted = false;
        
        function checkCounters() {
            if ($('.counter-number').length && !counted) {
                const oTop = $('.counter-number').offset().top - window.innerHeight;
                if ($(window).scrollTop() > oTop) {
                    $('.counter-number').each(function() {
                        const $this = $(this);
                        const countTo = parseInt($this.text(), 10);
                        
                        $({ countNum: $this.text() }).animate({ countNum: countTo }, {
                            duration: 2000,
                            easing: 'swing',
                            step: function() { $this.text(Math.floor(this.countNum) + '+'); },
                            complete: function() { $this.text(this.countNum + '+'); }
                        });
                    });
                    counted = true;
                    $(window).off('scroll', checkCounters);
                }
            }
        }
        
        $(window).on('scroll', checkCounters);
    }
    
})();